_verify_integrity() {
  if ! command -v sha256sum >/dev/null 2>&1; then
    echo "==> updatebtw: sha256sum not found, skipping integrity check" >&2
    return 0
  fi

  local current_hash
  current_hash="$(sed -n 's/^  echo "\(.*\)" | base64 -d > .*/\1/p' "$0" | sha256sum | awk '{print $1}')"

  if [ -n "$current_hash" ] && [ "$current_hash" != "$SOURCES_HASH" ]; then
    echo "==> updatebtw: WARNING — source integrity check failed!" >&2
    echo "    Expected: $SOURCES_HASH" >&2
    echo "    Got:      $current_hash" >&2
    echo "    The installer may have been tampered with." >&2
    return 1
  fi
  return 0
}

