_check_root() {
  if [ "$(id -u)" -ne 0 ]; then
    echo "This installer must be run as root." >&2
    exit 1
  fi
}

_check_deps() {
  local missing=""
  ! command -v whiptail >/dev/null 2>&1 && missing="$missing libnewt"
  ! command -v git >/dev/null 2>&1 && missing="$missing git"
  ! command -v sudo >/dev/null 2>&1 && missing="$missing sudo"
  ! pacman -Qi base-devel >/dev/null 2>&1 && missing="$missing base-devel"

  if [ -z "$missing" ]; then
    return 0
  fi

  if command -v whiptail >/dev/null 2>&1; then
    whiptail --title "Missing Dependencies" --yesno \
      "The following packages are required:\n\n$missing\n\nInstall them now?" \
      12 50 || exit 1
  else
    echo "Missing dependencies:$missing"
    printf "Install now? [Y/n] "
    read -r answer
    case "$answer" in
      n|N|no|NO) exit 1 ;;
    esac
  fi

  # shellcheck disable=SC2086
  pacman -S --needed --noconfirm $missing
}

_install_aur_helper() {
  local helper="$1" user="$2"
  command -v "$helper" >/dev/null 2>&1 && return 0

  if [ "$(id -un)" != "$user" ]; then
    if ! id "$user" >/dev/null 2>&1; then
      useradd -m "$user" 2>/dev/null || true
    fi
    mkdir -p /etc/sudoers.d
    cat > "/etc/sudoers.d/updatebtw-$user-build" << SUDOEOF
$user ALL=(root) NOPASSWD: /usr/bin/pacman, /usr/bin/makepkg
SUDOEOF
    chmod 440 "/etc/sudoers.d/updatebtw-$user-build"
  fi

  trap 'rm -f "/etc/sudoers.d/updatebtw-$user-build"' EXIT

  rm -rf "/tmp/$helper" 2>/dev/null || true
  if [ "$(id -un)" = "$user" ]; then
    git clone --depth=1 "https://aur.archlinux.org/$helper.git" "/tmp/$helper"
    cd "/tmp/$helper"
    makepkg -s --noconfirm
    sudo pacman -U --noconfirm *.pkg.tar.*
  else
    su - "$user" -c "
      git clone --depth=1 https://aur.archlinux.org/$helper.git /tmp/$helper
      cd /tmp/$helper
      makepkg -s --noconfirm
    "
    sudo pacman -U --noconfirm /tmp/$helper/*.pkg.tar.*
  fi && printf "Installed %s\n" "$helper" || printf "Warning: failed to install %s\n" "$helper"

  command -v "$helper" >/dev/null 2>&1
}

_setup_aur_user() {
  local user="$1"
  [ -n "$user" ] || return 1

  if ! id "$user" >/dev/null 2>&1; then
    useradd -m "$user" 2>/dev/null || true
  fi

  rm -f "/etc/sudoers.d/updatebtw-$user-build" 2>/dev/null || true
  rm -f "/etc/sudoers.d/updatebtw-$user" 2>/dev/null || true
  mkdir -p /etc/sudoers.d
  cat > "/etc/sudoers.d/updatebtw-$user" << SUDOEOF
$user ALL=(root) NOPASSWD: /usr/bin/pacman
SUDOEOF
  chmod 440 "/etc/sudoers.d/updatebtw-$user"
}

# === config module ===
# updatebtw config module

UPDATERBTW_CONFIG="${UPDATERBTW_CONFIG:-/etc/updatebtw/updatebtw.conf}"
AUR_USER="${AUR_USER:-aur_builder}"
FLATPAK_USER="${FLATPAK_USER:-${AUR_USER:-aur_builder}}"

_allowed_config_keys="AUR_HELPER UPDATE_FREQUENCY UPDATE_TIME RUN_AT_BOOT ENABLE_REFLECTOR REFLECTOR_COUNTRY REFLECTOR_PROTOCOL REFLECTOR_INTERVAL SILENT_BOOT AUR_USER FLATPAK_USER BLACKLIST_MODULES"

_safe_read_config() {
  local cfg="$1"
  [ -f "$cfg" ] || return 0

  if [ -L "$cfg" ]; then
    echo "updatebtw: config $cfg is a symlink, refusing" >&2
    return 1
  fi

  local perms
  perms="$(stat -c '%a' "$cfg" 2>/dev/null)" || return 1
  if [ "$perms" != "600" ] && [ "$perms" != "400" ]; then
    echo "updatebtw: config $cfg has unsafe permissions ($perms), expected 600 or 400" >&2
    return 1
  fi

  local owner
  owner="$(stat -c '%U' "$cfg" 2>/dev/null)" || return 1
  if [ "$owner" != "root" ]; then
    echo "updatebtw: config $cfg is not owned by root (owned by $owner)" >&2
    return 1
  fi

  local line key
  while IFS= read -r line; do
    case "$line" in
      ""|\#*) continue ;;
    esac
    key="${line%%=*}"
    key="$(printf '%s' "$key" | tr -d '[:space:]')"
    local allowed=false k
    for k in $_allowed_config_keys; do
      if [ "$key" = "$k" ]; then
        allowed=true
        break
      fi
    done
    if ! $allowed; then
      echo "updatebtw: config $cfg contains unknown key: $key" >&2
      return 1
    fi
    case "$line" in
      *'$('*|*'`'*|*';'*|*'&'*|*'|'*)
        echo "updatebtw: config $cfg contains dangerous syntax in: $line" >&2
        return 1
        ;;
    esac
    case "$line" in
      *'$(( '*|*'$[['*|*'${!'*)
        echo "updatebtw: config $cfg contains dangerous syntax in: $line" >&2
        return 1
        ;;
    esac
    if printf '%s' "$line" | grep -qE '(> |>>|<>|><|<\(|>\(|\$'\'')'; then
      echo "updatebtw: config $cfg contains dangerous syntax in: $line" >&2
      return 1
    fi
  done < "$cfg"

  local lock_file="${cfg}.lock"
  exec 9> "$lock_file"
  flock 9 || return 1

  . "$cfg"
  flock -u 9
  exec 9>&-
}

read_config() {
  _safe_read_config "$UPDATERBTW_CONFIG"
}

write_config() {
  local config_dir
  config_dir="$(dirname "$UPDATERBTW_CONFIG")"
  mkdir -p "$config_dir"
  local default_flatpak_user="${SUDO_USER:-}"
  [ -z "$default_flatpak_user" ] && default_flatpak_user="$(id -un)"
  cat > "$UPDATERBTW_CONFIG" << EOF
# updatebtw configuration
# Generated by updatebtw installer

AUR_HELPER="${AUR_HELPER:-yay}"
UPDATE_FREQUENCY="${UPDATE_FREQUENCY:-weekly}"
UPDATE_TIME="${UPDATE_TIME:-06:00}"
RUN_AT_BOOT="${RUN_AT_BOOT:-false}"
ENABLE_REFLECTOR="${ENABLE_REFLECTOR:-true}"
REFLECTOR_COUNTRY="${REFLECTOR_COUNTRY:-United States}"
REFLECTOR_PROTOCOL="${REFLECTOR_PROTOCOL:-https}"
REFLECTOR_INTERVAL="${REFLECTOR_INTERVAL:-30}"
SILENT_BOOT="${SILENT_BOOT:-false}"
BLACKLIST_MODULES="${BLACKLIST_MODULES:-sp5100_tco}"
AUR_USER="${AUR_USER:-aur_builder}"
FLATPAK_USER="${FLATPAK_USER:-$default_flatpak_user}"
EOF
  chmod 600 "$UPDATERBTW_CONFIG"
  chown root:root "$UPDATERBTW_CONFIG" 2>/dev/null || true
}

validate_config() {
  local errors=""
  case "${AUR_HELPER:-yay}" in
    yay|paru) ;;
    *) errors="${errors}error: AUR_HELPER must be 'yay' or 'paru' (got: ${AUR_HELPER})\n" ;;
  esac
  case "${UPDATE_FREQUENCY:-weekly}" in
    daily|weekly|monthly) ;;
    *) errors="${errors}error: UPDATE_FREQUENCY must be 'daily', 'weekly', or 'monthly' (got: ${UPDATE_FREQUENCY})\n" ;;
  esac
  if [ -n "$errors" ]; then
    printf '%b' "$errors" >&2
    return 1
  fi
  return 0
}

calendar_from_config() {
  local time="${UPDATE_TIME:-06:00}"
  case "${UPDATE_FREQUENCY:-weekly}" in
    daily)   echo "*-*-* ${time}:00" ;;
    weekly)  echo "Mon *-*-* ${time}:00" ;;
    monthly) echo "*-*-01 ${time}:00" ;;
  esac
}

# === backup module ===
# updatebtw backup module

UPDATERBTW_BACKUP_DIR="${UPDATERBTW_BACKUP_DIR:-/var/lib/updatebtw/backups}"
UPDATERBTW_BACKUP_KEEP="${UPDATERBTW_BACKUP_KEEP:-10}"
UPDATERBTW_BACKUP_MANIFEST="${UPDATERBTW_BACKUP_MANIFEST:-/var/lib/updatebtw/backups/.manifest}"

backup_file() {
  local src="$1"
  [ -f "$src" ] || return 1
  mkdir -p "$UPDATERBTW_BACKUP_DIR"
  chmod 700 "$UPDATERBTW_BACKUP_DIR"
  local name
  name="$(basename "$src")"
  local ts rand
  ts="$(date "+%Y%m%d_%H%M%S")"
  rand="$(head -c 4 /dev/urandom | od -An -tx4 | tr -d ' ')"
  cp -a "$src" "$UPDATERBTW_BACKUP_DIR/${name}.${ts}.${rand}"
  chmod 600 "$UPDATERBTW_BACKUP_DIR/${name}.${ts}.${rand}"
  chown root:root "$UPDATERBTW_BACKUP_DIR/${name}.${ts}.${rand}" 2>/dev/null || true

  mkdir -p "$(dirname "$UPDATERBTW_BACKUP_MANIFEST")"
  grep -qxF "$src" "$UPDATERBTW_BACKUP_MANIFEST" 2>/dev/null || echo "$src" >> "$UPDATERBTW_BACKUP_MANIFEST"
  chmod 600 "$UPDATERBTW_BACKUP_MANIFEST" 2>/dev/null || true

  _rotate_backups "$name"
}

restore_file() {
  local src="$1"

  if [ -f "$UPDATERBTW_BACKUP_MANIFEST" ]; then
    if ! grep -qxF "$src" "$UPDATERBTW_BACKUP_MANIFEST"; then
      echo "updatebtw: $src has no backup, refusing restore" >&2
      return 1
    fi
  fi

  local name
  name="$(basename "$src")"
  local latest
  latest="$(ls -t "$UPDATERBTW_BACKUP_DIR/${name}."* 2>/dev/null | head -1)"
  [ -n "$latest" ] || return 1
  cp -a "$latest" "$src"
}

list_backups() {
  local name="${1:-}"
  if [ -n "$name" ]; then
    find "$UPDATERBTW_BACKUP_DIR" -maxdepth 1 -name "${name}.*" -printf '%f\n' 2>/dev/null | sort -r || true
  else
    find "$UPDATERBTW_BACKUP_DIR" -maxdepth 1 -type f -printf '%f\n' 2>/dev/null | sort -r || true
  fi
}

_rotate_backups() {
  local name="$1"
  local keep="${UPDATERBTW_BACKUP_KEEP:-10}"
  ls -t "$UPDATERBTW_BACKUP_DIR/${name}."* 2>/dev/null \
    | tail -n +$((keep + 1)) \
    | xargs rm -f 2>/dev/null || true
}

_cleanup_old_backups() {
  [ -d "$UPDATERBTW_BACKUP_DIR" ] || return 0
  find "$UPDATERBTW_BACKUP_DIR" -type f -mtime +60 -delete 2>/dev/null || true
}

# === silent-boot module ===
# updatebtw silent boot module

BLACKLIST_MODULES="${BLACKLIST_MODULES:-sp5100_tco}"

detect_bootloader() {
  [ -f /boot/loader/loader.conf ] && echo "systemd-boot" && return 0
  [ -f /etc/default/grub ] && echo "grub" && return 0
  echo "unknown"
  return 0
}

set_kernel_options() {
  local entries_dir="${1:-/boot/loader/entries}"
  local kernel_options="${2:-quiet loglevel=3 vt.global_cursor_default=0 systemd.show_status=auto rd.udev.log_level=3}"
  if [ -n "$BLACKLIST_MODULES" ]; then
    kernel_options="$kernel_options modprobe.blacklist=$BLACKLIST_MODULES"
  fi

  read -ra option_tokens <<< "$kernel_options"
  local option_keys=()
  local token
  for token in "${option_tokens[@]}"; do
    option_keys+=("${token%%=*}")
  done

  [ -d "$entries_dir" ] || return 0
  local entry
  for entry in "$entries_dir"/*; do
    [ -f "$entry" ] || continue
    backup_file "$entry" 2>/dev/null || true

    local tmpfile
    tmpfile="$(mktemp "${entry}.XXXXXX")"
    chmod 644 "$tmpfile"
    chown root:root "$tmpfile"
    local line

    while IFS= read -r line; do
      read -ra line_tokens <<< "$line"
      if [ "${line_tokens[0]}" = "options" ]; then
        local out_line=""
        local token2 key2 skip
        for token2 in "${line_tokens[@]}"; do
          key2="${token2%%=*}"
          skip=false
          local k
          for k in "${option_keys[@]}"; do
            if [ "$key2" = "$k" ]; then
              skip=true
              break
            fi
          done
          if ! $skip; then
            out_line="$out_line$token2 "
          fi
        done
        out_line="$out_line$kernel_options"
        printf '%s\n' "$out_line" >> "$tmpfile"
      else
        printf '%s\n' "$line" >> "$tmpfile"
      fi
    done < "$entry"

    mv "$tmpfile" "$entry"
  done
}

set_grub_silent() {
  local grub_cfg="${1:-/etc/default/grub}"
  [ -f "$grub_cfg" ] || return 0

  backup_file "$grub_cfg" 2>/dev/null || true

  local tmpfile
  tmpfile="$(mktemp "${grub_cfg}.XXXXXX")"
  chmod 644 "$tmpfile"
  chown root:root "$tmpfile"

  local has_default=false has_timeout=false has_recordfail=false

  while IFS= read -r line; do
    local key="${line%%=*}"
    key="${key## }"
    case "$key" in
      GRUB_DEFAULT)
        printf 'GRUB_DEFAULT=0\n' >> "$tmpfile"
        has_default=true
        ;;
      GRUB_TIMEOUT)
        printf 'GRUB_TIMEOUT=0\n' >> "$tmpfile"
        has_timeout=true
        ;;
      GRUB_RECORDFAIL_TIMEOUT)
        printf 'GRUB_RECORDFAIL_TIMEOUT=$GRUB_TIMEOUT\n' >> "$tmpfile"
        has_recordfail=true
        ;;
      *)
        printf '%s\n' "$line" >> "$tmpfile"
        ;;
    esac
  done < "$grub_cfg"

  if ! $has_default; then
    printf 'GRUB_DEFAULT=0\n' >> "$tmpfile"
  fi
  if ! $has_timeout; then
    printf 'GRUB_TIMEOUT=0\n' >> "$tmpfile"
  fi
  if ! $has_recordfail; then
    printf 'GRUB_RECORDFAIL_TIMEOUT=$GRUB_TIMEOUT\n' >> "$tmpfile"
  fi

  mv "$tmpfile" "$grub_cfg"

  if command -v grub-mkconfig >/dev/null 2>&1; then
    grub-mkconfig -o /boot/grub/grub.cfg 2>/dev/null || true
  fi
}

set_printk() {
  local dest="${1:-/etc/sysctl.d/20-quiet-printk.conf}"
  local dest_dir
  dest_dir="$(dirname "$dest")"
  mkdir -p "$dest_dir"
  backup_file "$dest" 2>/dev/null || true
  printf 'kernel.printk = 3 3 3 3\n' > "$dest"
}

patch_mkinitcpio() {
  local src="${1:-/etc/mkinitcpio.conf}"
  [ -f "$src" ] || return 0
  backup_file "$src" 2>/dev/null || true

  local tmpfile
  tmpfile="$(mktemp "${src}.XXXXXX")"
  chmod 644 "$tmpfile"
  chown root:root "$tmpfile"
  local line

  while IFS= read -r line; do
    local key="${line%%=*}"
    key="${key## }"
    if [ "$key" = "HOOKS" ]; then
      local result="" trailing_paren="" token
      for token in $line; do
        local base="$token" has_paren=false
        case "$token" in
          *")")
            base="${token%)}"
            has_paren=true
            ;;
        esac
        case "$base" in
          udev)
            result="$result systemd"
            $has_paren && trailing_paren=")"
            ;;
          fsck)
            $has_paren && trailing_paren=")"
            continue
            ;;
          *)
            result="$result $base"
            $has_paren && trailing_paren=")"
            ;;
        esac
      done
      line="${result# }${trailing_paren}"
      printf '%s\n' "$line" >> "$tmpfile"
    else
      printf '%s\n' "$line" >> "$tmpfile"
    fi
  done < "$src"

  mv "$tmpfile" "$src"
}

patch_fsck_services() {
  local files=("$@")
  if [ ${#files[@]} -eq 0 ]; then
    files=(/usr/lib/systemd/system/systemd-fsck@.service /usr/lib/systemd/system/systemd-fsck-root.service)
  fi

  local file
  for file in "${files[@]}"; do
    [ -f "$file" ] || continue
    backup_file "$file" 2>/dev/null || true

    local tmpfile
    tmpfile="$(mktemp "${file}.XXXXXX")"
    chmod 644 "$tmpfile"
    chown root:root "$tmpfile"
    local in_service=false
    local line key

    while IFS= read -r line; do
      key="${line%%=*}"
      if [ "$line" = "[Service]" ]; then
        in_service=true
        printf '%s\n' "$line" >> "$tmpfile"
        printf 'StandardOutput=null\n' >> "$tmpfile"
        printf 'StandardError=journal+console\n' >> "$tmpfile"
      elif $in_service && { [ "$key" = "StandardOutput" ] || [ "$key" = "StandardError" ]; }; then
        :
      else
        printf '%s\n' "$line" >> "$tmpfile"
      fi
    done < "$file"

    mv "$tmpfile" "$file"
  done
}

silent_boot() {
  local bootloader
  bootloader="$(detect_bootloader)"
  case "$bootloader" in
    systemd-boot)
      if [ ! -d /boot/loader/entries ] || [ -z "$(ls /boot/loader/entries/*.conf 2>/dev/null)" ]; then
        echo "Warning: No systemd-boot entries found — skipping kernel option changes" >&2
      else
        set_kernel_options
      fi
      ;;
    grub)
      if [ ! -f /etc/default/grub ]; then
        echo "Warning: GRUB config not found — skipping GRUB changes" >&2
      else
        set_grub_silent
      fi
      ;;
    unknown)
      echo "Warning: Unknown bootloader — skipping bootloader-specific changes"
      ;;
  esac

  set_printk
  patch_mkinitcpio
  patch_fsck_services

  if [ -f /etc/mkinitcpio.conf ] && [ -f /boot/vmlinuz-linux ]; then
    mkinitcpio -P || {
      echo "ERROR: mkinitcpio failed — restoring backup of mkinitcpio.conf" >&2
      restore_file /etc/mkinitcpio.conf 2>/dev/null || true
      return 1
    }
  fi

  touch ~root/.hushlogin
  touch ~"${SUDO_USER:-$(id -un)}"/.hushlogin 2>/dev/null || true

  systemctl unmask systemd-journald-audit.socket 2>/dev/null || true
  systemctl stop systemd-journald-audit.socket 2>/dev/null || true
  systemctl disable systemd-journald-audit.socket 2>/dev/null || true
  systemctl mask systemd-journald-audit.socket 2>/dev/null || true
}

# === updater module ===
# updatebtw updater module

UPDATERBTW_STATE_DIR="${UPDATERBTW_STATE_DIR:-/var/lib/updatebtw}"
: "${UPDATERBTW_MIN_UPDATE_INTERVAL:=300}"
_update_lock_fd=""

_check_rate_limit() {
  local state_file="$UPDATERBTW_STATE_DIR/last_update"
  local lock_file="$UPDATERBTW_STATE_DIR/update.lock"
  mkdir -p "$UPDATERBTW_STATE_DIR"

  exec 8> "$lock_file"
  if ! flock -n 8; then
    _notify error "Update In Progress" "Another update is already running"
    return 1
  fi
  _update_lock_fd=8

  if [ -f "$state_file" ]; then
    local last_update now delta
    last_update="$(cat "$state_file")"
    now="$(date "+%s")"
    delta=$(( now - last_update ))
    if [ "$delta" -lt "$UPDATERBTW_MIN_UPDATE_INTERVAL" ]; then
      _notify error "Update Throttled" "Last update was $(( delta ))s ago, minimum interval is ${UPDATERBTW_MIN_UPDATE_INTERVAL}s"
      return 1
    fi
  fi

  date "+%s" > "$state_file"
  return 0
}

update_packages() {
  trap '_notify critical "updatebtw" "Shutdown blocked — system update in progress, please wait"' SIGTERM
  read_config

  if ! _check_rate_limit; then
    return 1
  fi

  _cleanup_old_backups 2>/dev/null || true
  _cleanup_old_logs 2>/dev/null || true

  if [ -e /var/lib/pacman/db.lck ]; then
    _notify error "Update Failed" "/var/lib/pacman/db.lck exists"
    return 1
  fi

  local pacman_lock="$UPDATERBTW_STATE_DIR/pacman.lock"
  exec 7> "$pacman_lock"
  if ! flock -n 7; then
    _notify error "Update Failed" "Another pacman process holds the database lock"
    return 1
  fi

  if [ "${ENABLE_REFLECTOR:-true}" = "true" ]; then
    _update_mirrorlist || true
  fi

  _notify info "updatebtw" "Starting system update"
  local helper="${AUR_HELPER:-yay}"
  local aur_user="${AUR_USER:-aur_builder}"
  case "$helper" in
    yay)  _run_as_user "$aur_user" yay -Syyuu --noconfirm ;;
    paru) _run_as_user "$aur_user" paru -Syyuu --noconfirm ;;
  esac

  local exit_code=$?
  if [ $exit_code -ne 0 ]; then
    _notify error "Update Failed" "AUR helper exited with code $exit_code"
    return $exit_code
  fi

  if command -v flatpak >/dev/null 2>&1; then
    local flatpak_user="${FLATPAK_USER:-$aur_user}"
    _run_as_user "$flatpak_user" flatpak update --noninteractive || {
      _notify error "Flatpak Update Failed" "flatpak exited with code $?"
      return 1
    }
  fi

  _notify success "updatebtw" "Update complete"
  [ -n "$_update_lock_fd" ] && flock -u "$_update_lock_fd" 2>/dev/null || true
  flock -u 7 2>/dev/null || true
  rm -f "$pacman_lock" 2>/dev/null || true
}

_update_mirrorlist() {
  local mirrorlist="/etc/pacman.d/mirrorlist"
  local interval=$(( ${REFLECTOR_INTERVAL:-30} * 86400 ))

  if [ -f "$mirrorlist" ]; then
    local last_update
    last_update="$(date -r "$mirrorlist" "+%s")"
    local now
    now="$(date "+%s")"
    local delta=$(( now - last_update ))
    if [ $delta -lt $interval ]; then
      return 0
    fi
  fi

  backup_file "$mirrorlist"
  _notify info "updatebtw" "Updating mirrorlist via reflector"
  if ! timeout 120 reflector --save "$mirrorlist" \
       --country "${REFLECTOR_COUNTRY:-United States}" \
       --protocol "${REFLECTOR_PROTOCOL:-https}" \
       --latest 5 \
       --sort age \
       --age 12 \
       --connection-timeout 10; then
    _notify error "Reflector Failed" "Mirrorlist update failed"
    return 1
  fi
}

_notify() {
  local type="$1"
  local summary="$2"
  local body="$3"
  if [ "$type" = "error" ] && [ -n "$UPDATERBTW_LOG_FILE" ]; then
    body="$body — see $UPDATERBTW_LOG_FILE"
  fi
  echo "[$type] $summary: $body"
  if ! command -v notify-send >/dev/null 2>&1; then
    return 0
  fi

  local urgency="normal"
  local icon="dialog-information"
  case "$type" in
    error)    urgency="critical"; icon="dialog-error" ;;
    success)  urgency="normal";   icon="dialog-information" ;;
    info)     urgency="low";      icon="dialog-information" ;;
    critical) urgency="critical"; icon="dialog-warning" ;;
  esac

  local target_user="${SUDO_USER:-}"
  if [ -z "$target_user" ]; then
    target_user="$(loginctl list-sessions --no-legend 2>/dev/null | while read -r sid uid rest; do
      local stype
      stype="$(loginctl show-session "$sid" -p Type --value 2>/dev/null)"
      if [ "$stype" = "x11" ] || [ "$stype" = "wayland" ]; then
        id -un "$uid" 2>/dev/null && break
      fi
    done)"
    [ -z "$target_user" ] && target_user="$(loginctl list-sessions --no-legend 2>/dev/null | awk '{print $2}' | head -1)"
    [ -n "$target_user" ] && target_user="$(id -un "$target_user" 2>/dev/null)" || target_user=""
  fi

  if [ -n "$target_user" ]; then
    local uid
    uid="$(id -u "$target_user" 2>/dev/null)" || return 0
    if [ -S "/run/user/$uid/bus" ]; then
      if [ "$(id -un)" = "$target_user" ]; then
        notify-send -i "$icon" -u "$urgency" -a "updatebtw" "$summary" "$body" 2>/dev/null || true
      elif command -v runuser >/dev/null 2>&1; then
        runuser -u "$target_user" -- env \
          XDG_RUNTIME_DIR="/run/user/$uid" \
          DBUS_SESSION_BUS_ADDRESS="unix:path=/run/user/$uid/bus" \
          notify-send -i "$icon" -u "$urgency" -a "updatebtw" "$summary" "$body" 2>/dev/null || true
      else
        su - "$target_user" -c "XDG_RUNTIME_DIR=/run/user/$uid DBUS_SESSION_BUS_ADDRESS=unix:path=/run/user/$uid/bus notify-send -i '$icon' -u '$urgency' -a 'updatebtw' '$summary' '$body'" 2>/dev/null || true
      fi
    fi
  else
    notify-send -i "$icon" -u "$urgency" -a "updatebtw" "$summary" "$body" 2>/dev/null || true
  fi
  return 0
}

_run_as_user() {
  local user="$1"
  shift
  if [ "$(id -un)" = "$user" ]; then
    "$@"
  elif command -v runuser >/dev/null 2>&1; then
    runuser -u "$user" -- "$@"
  elif command -v sudo >/dev/null 2>&1; then
    sudo -u "$user" -- "$@"
  else
    echo "updatebtw: cannot run as user '$user' — neither runuser nor sudo available" >&2
    return 1
  fi
}

_cleanup_old_logs() {
  local log_dir="${UPDATERBTW_LOG_DIR:-/var/log/updatebtw}"
  [ -d "$log_dir" ] || return 0
  find "$log_dir" -type f -mtime +60 -delete 2>/dev/null || true
}

